#include <stdio.h>
#include <string.h>

int main() {
    // --- Arrays Demo ---
    int a[2][2] = {{1, 2}, {3, 4}};
    int b[2][2] = {{5, 6}, {7, 8}};
    int sum[2][2];

    printf("--- Matrix Addition ---\n");
    // Nested loops for 2D arrays
    for(int i=0; i<2; i++) {
        for(int j=0; j<2; j++) {
            sum[i][j] = a[i][j] + b[i][j];
            printf("%d ", sum[i][j]);
        }
        printf("\n");
    }

    // --- Strings Demo ---
    printf("\n--- String Operations ---\n");
    char first[20] = "Code";
    char second[] = "Quiz";

    // Concatenation
    strcat(first, second);
    printf("Combined: %s\n", first);

    // Length
    printf("Length: %lu\n", strlen(first));

    // Comparison
    if(strcmp(first, "CodeQuiz") == 0) {
        printf("Strings match!\n");
    }

    return 0;
}
